exercises.canonical_solution:
def is_anagram(s1, s2):
    s1 = s1.lower()
    s2 = s2.lower()
    counts = {}
    for ch in s1:
        counts[ch] = counts.get(ch, 0) + 1
    for ch in s2:
        counts[ch] = counts.get(ch, 0) - 1
    return all(v == 0 for v in counts.values())

